import{_ as t,o as a,c as i,a2 as n}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"Ultimate Testing & Verification Protocol","description":"The mandatory proof-of-work testing doctrine for OpenSIN agents, SDK modules, web apps, and infrastructure.","frontmatter":{"title":"Ultimate Testing & Verification Protocol","description":"The mandatory proof-of-work testing doctrine for OpenSIN agents, SDK modules, web apps, and infrastructure."},"headers":[],"relativePath":"best-practices/testing.md","filePath":"best-practices/testing.md"}'),r={name:"best-practices/testing.md"};function o(s,e,l,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="ultimate-testing-verification-protocol" tabindex="-1">Ultimate Testing &amp; Verification Protocol <a class="header-anchor" href="#ultimate-testing-verification-protocol" aria-label="Permalink to &quot;Ultimate Testing &amp; Verification Protocol&quot;">​</a></h1><blockquote><p><strong>ABSOLUTE RULE:</strong> Nothing is done until reality proves it. A green-looking diff, a persuasive explanation, or a static code review is <strong>not</strong> evidence. The only valid proof is a successful real execution with logs, output, screenshots, or trace artifacts.</p></blockquote><hr><h2 id="_1-the-100-test-proof-mandate" tabindex="-1">1. The 100% Test-Proof Mandate <a class="header-anchor" href="#_1-the-100-test-proof-mandate" aria-label="Permalink to &quot;1. The 100% Test-Proof Mandate&quot;">​</a></h2><h3 id="what" tabindex="-1">WHAT <a class="header-anchor" href="#what" aria-label="Permalink to &quot;WHAT&quot;">​</a></h3><p>Every change must be verified by a real execution path appropriate to the change:</p><ul><li>code path → unit/integration/runtime test</li><li>UI path → browser verification + screenshot</li><li>API path → real request/response check</li><li>workflow path → real run in n8n / queue / webhook</li><li>deploy path → live URL check</li></ul><h3 id="why" tabindex="-1">WHY <a class="header-anchor" href="#why" aria-label="Permalink to &quot;WHY&quot;">​</a></h3><p>Large autonomous systems fail most often at runtime boundaries: imports, environment variables, asset paths, auth, network, browser state, race conditions. These are invisible to “looks correct” reasoning.</p><h3 id="why-not-otherwise" tabindex="-1">WHY NOT OTHERWISE <a class="header-anchor" href="#why-not-otherwise" aria-label="Permalink to &quot;WHY NOT OTHERWISE&quot;">​</a></h3><p>If you allow agents to declare success from code inspection alone, the fleet fills with half-fixes and ceremonial patches that collapse on first contact with production.</p><h3 id="dependencies" tabindex="-1">DEPENDENCIES <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;DEPENDENCIES&quot;">​</a></h3><p>This rule directly depends on:</p><ul><li>the absolute no-assumptions mandate</li><li>Box.com Storage (A2A-SIN-Box-Storage) for evidence retention</li><li>browser automation tooling for UI proof</li><li>issue tracking for public incident memory</li></ul><h3 id="consequences" tabindex="-1">CONSEQUENCES <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;CONSEQUENCES&quot;">​</a></h3><p>Any task closed without proof is invalid. The fix must be reopened and retested.</p><hr><h2 id="_2-testing-pyramid-reinterpreted-for-agents" tabindex="-1">2. Testing Pyramid, Reinterpreted for Agents <a class="header-anchor" href="#_2-testing-pyramid-reinterpreted-for-agents" aria-label="Permalink to &quot;2. Testing Pyramid, Reinterpreted for Agents&quot;">​</a></h2><p>Traditional pyramids still matter, but in agentic systems the top matters more than people think because orchestration, tool-calling, and remote systems are where most failures live.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              ┌───────────────────────────────┐</span></span>
<span class="line"><span>              │  LIVE / DEPLOY VERIFICATION   │</span></span>
<span class="line"><span>              │  real URL, webhook, session   │</span></span>
<span class="line"><span>              └───────────────────────────────┘</span></span>
<span class="line"><span>                    ┌─────────────────────┐</span></span>
<span class="line"><span>                    │  E2E / WORKFLOW     │</span></span>
<span class="line"><span>                    │  browser + API + DB │</span></span>
<span class="line"><span>                    └─────────────────────┘</span></span>
<span class="line"><span>                 ┌──────────────────────────┐</span></span>
<span class="line"><span>                 │  INTEGRATION / CONTRACT  │</span></span>
<span class="line"><span>                 │  adapters, MCP, A2A, n8n │</span></span>
<span class="line"><span>                 └──────────────────────────┘</span></span>
<span class="line"><span>               ┌──────────────────────────────┐</span></span>
<span class="line"><span>               │  UNIT / SYMBOL-LEVEL LOGIC   │</span></span>
<span class="line"><span>               │  pure functions, transforms  │</span></span>
<span class="line"><span>               └──────────────────────────────┘</span></span></code></pre></div><h3 id="practical-interpretation" tabindex="-1">Practical interpretation <a class="header-anchor" href="#practical-interpretation" aria-label="Permalink to &quot;Practical interpretation&quot;">​</a></h3><ul><li><strong>Unit tests</strong> protect transformations and pure logic.</li><li><strong>Integration tests</strong> protect boundaries between modules and tools.</li><li><strong>E2E tests</strong> prove the user story.</li><li><strong>Live verification</strong> proves the deployment actually reflects the code.</li></ul><hr><h2 id="_3-required-test-types-by-change-class" tabindex="-1">3. Required Test Types by Change Class <a class="header-anchor" href="#_3-required-test-types-by-change-class" aria-label="Permalink to &quot;3. Required Test Types by Change Class&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Change Type</th><th>Minimum Required Proof</th></tr></thead><tbody><tr><td>Pure utility / parser</td><td>unit tests + one representative CLI or runtime call</td></tr><tr><td>SDK module / shared package</td><td>unit + integration + consumer build check</td></tr><tr><td>MCP / adapter / plugin</td><td>contract test + real tool invocation</td></tr><tr><td>n8n workflow</td><td>test execution + node output verification</td></tr><tr><td>Website UI</td><td>browser load + critical flow + screenshot</td></tr><tr><td>Deployment / infra</td><td>live endpoint health check + artifact evidence</td></tr><tr><td>Auth / permissions</td><td>explicit success + explicit denial test</td></tr></tbody></table><hr><h2 id="_4-mandatory-testing-behavior-for-agents" tabindex="-1">4. Mandatory Testing Behavior for Agents <a class="header-anchor" href="#_4-mandatory-testing-behavior-for-agents" aria-label="Permalink to &quot;4. Mandatory Testing Behavior for Agents&quot;">​</a></h2><h3 id="_4-1-before-editing" tabindex="-1">4.1 Before editing <a class="header-anchor" href="#_4-1-before-editing" aria-label="Permalink to &quot;4.1 Before editing&quot;">​</a></h3><p>The agent must identify:</p><ul><li>what can break</li><li>what proof would actually prove correctness</li><li>what existing validation command the repo already uses</li></ul><h3 id="_4-2-during-editing" tabindex="-1">4.2 During editing <a class="header-anchor" href="#_4-2-during-editing" aria-label="Permalink to &quot;4.2 During editing&quot;">​</a></h3><p>The agent should test incrementally after meaningful milestones, not only at the end.</p><h3 id="_4-3-before-claiming-done" tabindex="-1">4.3 Before claiming done <a class="header-anchor" href="#_4-3-before-claiming-done" aria-label="Permalink to &quot;4.3 Before claiming done&quot;">​</a></h3><p>The agent must provide:</p><ol><li>command(s) run</li><li>exact outcome</li><li>what those outcomes prove</li><li>what remains unproven</li></ol><p>If something remains unproven, the task is not done.</p><hr><h2 id="_5-browser-verification-requirements" tabindex="-1">5. Browser Verification Requirements <a class="header-anchor" href="#_5-browser-verification-requirements" aria-label="Permalink to &quot;5. Browser Verification Requirements&quot;">​</a></h2><p>For any UI change, the following is mandatory:</p><ul><li>page loads with no fatal error</li><li>key visible elements confirmed</li><li>important interactions clicked</li><li>screenshot captured for success state</li><li>screenshot captured for failure state if any issue appears</li><li>console errors checked if behavior is suspicious</li></ul><h3 id="why-this-matters" tabindex="-1">Why this matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why this matters&quot;">​</a></h3><p>UI regressions often hide in CSS, hydration, route loading, or event wiring. A passing build proves almost nothing about visible correctness.</p><hr><h2 id="_6-workflow-n8n-verification-requirements" tabindex="-1">6. Workflow / n8n Verification Requirements <a class="header-anchor" href="#_6-workflow-n8n-verification-requirements" aria-label="Permalink to &quot;6. Workflow / n8n Verification Requirements&quot;">​</a></h2><p>For any workflow change, the agent must verify:</p><ul><li>trigger fires</li><li>downstream nodes receive expected shape</li><li>side effects occur (issue created, message sent, file written, etc.)</li><li>failure path is visible and understandable</li><li>execution history is inspectable</li></ul><h3 id="required-evidence" tabindex="-1">Required evidence <a class="header-anchor" href="#required-evidence" aria-label="Permalink to &quot;Required evidence&quot;">​</a></h3><ul><li>execution ID or screenshot/log of execution</li><li>output payload snippet</li><li>confirmation of the side effect in the target system</li></ul><hr><h2 id="_7-contract-testing-for-shared-systems" tabindex="-1">7. Contract Testing for Shared Systems <a class="header-anchor" href="#_7-contract-testing-for-shared-systems" aria-label="Permalink to &quot;7. Contract Testing for Shared Systems&quot;">​</a></h2><p>When multiple repos consume the same module (<code>@opensin/ui</code>, MCP contracts, shared adapters), test the provider and at least one consumer.</p><h3 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>A shared package can be valid in isolation but broken in consumer resolution, bundling, CSS order, or type exports.</p><h3 id="minimum-proof-for-shared-packages" tabindex="-1">Minimum proof for shared packages <a class="header-anchor" href="#minimum-proof-for-shared-packages" aria-label="Permalink to &quot;Minimum proof for shared packages&quot;">​</a></h3><ul><li>package builds</li><li>consumer app installs/links it</li><li>consumer app build passes</li><li>one visible consumer behavior proves integration</li></ul><hr><h2 id="_8-false-success-anti-patterns" tabindex="-1">8. False Success Anti-Patterns <a class="header-anchor" href="#_8-false-success-anti-patterns" aria-label="Permalink to &quot;8. False Success Anti-Patterns&quot;">​</a></h2><p>Reject all of these:</p><ul><li>“TypeScript compiles, so it works.”</li><li>“The code looks correct.”</li><li>“The component renders in theory.”</li><li>“The webhook should fire.”</li><li>“It passed once locally without logs.”</li><li>“The PR is small so tests are unnecessary.”</li></ul><p>Each of those is not proof. Each is just hope.</p><hr><h2 id="_9-required-artifact-retention" tabindex="-1">9. Required Artifact Retention <a class="header-anchor" href="#_9-required-artifact-retention" aria-label="Permalink to &quot;9. Required Artifact Retention&quot;">​</a></h2><p>All meaningful verification should leave artifacts when possible:</p><ul><li>screenshots</li><li>execution logs</li><li>terminal output</li><li>PR comments</li><li>issue updates</li><li>deployment URLs</li></ul><p>When the project is covered by Box.com Storage, upload artifacts there instead of leaving them only in <code>/tmp</code>.</p><hr><h2 id="_10-recommended-validation-checklist-before-merge" tabindex="-1">10. Recommended Validation Checklist Before Merge <a class="header-anchor" href="#_10-recommended-validation-checklist-before-merge" aria-label="Permalink to &quot;10. Recommended Validation Checklist Before Merge&quot;">​</a></h2><ul><li>[ ] Repo-native lint/build/type checks pass</li><li>[ ] Runtime proof exists</li><li>[ ] Browser proof exists if UI changed</li><li>[ ] Workflow proof exists if automation changed</li><li>[ ] Shared consumer proof exists if package changed</li><li>[ ] Failure path was considered</li><li>[ ] Evidence retained in logs / screenshots / issue / PR</li></ul><hr><h2 id="_11-example-verification-statements" tabindex="-1">11. Example Verification Statements <a class="header-anchor" href="#_11-example-verification-statements" aria-label="Permalink to &quot;11. Example Verification Statements&quot;">​</a></h2><h3 id="good" tabindex="-1">Good <a class="header-anchor" href="#good" aria-label="Permalink to &quot;Good&quot;">​</a></h3><ul><li><code>bun ./scripts/build-docs.mjs</code> passed, proving the docs bundle compiles end-to-end.</li><li>Browser loaded <code>https://blog.opensin.ai</code> and displayed the shared header/footer; screenshot saved.</li><li>n8n execution <code>2200</code> completed successfully and wrote the markdown file to the blog repo.</li></ul><h3 id="bad" tabindex="-1">Bad <a class="header-anchor" href="#bad" aria-label="Permalink to &quot;Bad&quot;">​</a></h3><ul><li>“Looks fine now.”</li><li>“Should be good.”</li><li>“Probably fixed.”</li></ul><hr><h2 id="_12-final-rule" tabindex="-1">12. Final Rule <a class="header-anchor" href="#_12-final-rule" aria-label="Permalink to &quot;12. Final Rule&quot;">​</a></h2><p><strong>Testing is not a cleanup step. It is the proof layer of engineering.</strong> If proof is absent, the work is absent.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Test-Beweis-Pflicht</strong></td><td>0.0</td><td>KEIN &quot;Done&quot; ohne echten Test-Lauf</td></tr><tr><td><strong>Annahmen-Verbot</strong></td><td>-5.0</td><td>KEINE Diagnose ohne Beweis</td></tr><tr><td><strong>Visual Evidence</strong></td><td>0.0</td><td>Jeder Fix MUSS visuell belegt werden</td></tr></tbody></table>`,82)])])}const m=t(r,[["render",o]]);export{u as __pageData,m as default};
